#include <stdio.h>
#include <string.h>

void decodeDNA(int n, const char *s, char *out) {
    int k = 0;
    for (int i = 0; i < n; i += 2) {
        if (s[i] == '0' && s[i+1] == '0') out[k++] = 'A';
        else if (s[i] == '0' && s[i+1] == '1') out[k++] = 'T';
        else if (s[i] == '1' && s[i+1] == '0') out[k++] = 'C';
        else out[k++] = 'G';
    }
    out[k] = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        char s[1010];
        char ans[510];
        scanf("%d", &n);
        scanf("%s", s);
        decodeDNA(n, s, ans);
        printf("%s\n", ans);
    }
    return 0;
}

