#include <bits/stdc++.h>
using namespace std;

string decodeDNA(int n, const string &s) {
    string res;
    res.reserve(n/2);
    for (int i = 0; i < n; i += 2) {
        if (s[i] == '0' && s[i+1] == '0') res.push_back('A');
        else if (s[i] == '0' && s[i+1] == '1') res.push_back('T');
        else if (s[i] == '1' && s[i+1] == '0') res.push_back('C');
        else res.push_back('G');
    }
    return res;
}

