import sys

def decodeDNA(n, s):
    res = []
    for i in range(0, n, 2):
        pair = s[i:i+2]
        if pair == '00':
            res.append('A')
        elif pair == '01':
            res.append('T')
        elif pair == '10':
            res.append('C')
        else:
            res.append('G')
    return ''.join(res)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        s = next(it)
        out_lines.append(decodeDNA(n, s))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

